    description: "Role for application developers",
    rules: [{
        resources: [
            "pods",
            "services",
            "deployments",
            "configmaps",
        ],
        verbs: [
            "get",
            "list",
            "watch",
            "create",
            "update",
            "delete",
            "patch",
        ],
        apiGroups: [
            "",
            "apps",
        ],
    }],
});
