thalassa:index/securityGroup:SecurityGro.description:
A security group is a collection of rules that control the traffic to and from a virtual machine instance or other cloud resource within a VPC.

## Example Usage

<!--Start PulumiCodeChooser -->
```typescript
import * as pulumi from "@pulumi/pulumi";
import * as thalassa from "@sandervb2/pulumi-thalassa";

const exampleVpc = new thalassa.Vpc("exampleVpc", {
    description: "Example VPC for security group",
    region: "nl-01",
    cidrs: ["10.0.0.0/16"],
});
// Create a security group
const exampleSecurityGroup = new thalassa.SecurityGroup("exampleSecurityGroup", {
    description: "Example security group",
    vpcId: exampleVpc.id,
    allowSameGroupTraffic: false,
    ingressRules: [
        {
            name: "allow-http",
            ipVersion: "ipv4",
            protocol: "tcp",
            priority: 100,
            remoteType: "address",
            remoteAddress: "10.0.0.0/0",
            portRangeMin: 80,
            portRangeMax: 80,
            policy: "allow",
        },
        {
            name: "allow-https",
            ipVersion: "ipv4",
            protocol: "tcp",
            priority: 101,
            remoteType: "address",
            remoteAddress: "0.0.0.0/0",
            portRangeMin: 443,
            portRangeMax: 443,
            policy: "allow",
        },
    ],
    egressRules: [{
        name: "allow-all",
        ipVersion: "ipv4",
        protocol: "all",
        priority: 100,
        remoteType: "address",
        remoteAddress: "0.0.0.0/0",
        policy: "allow",
    }],
});
export const securityGroupId = exampleSecurityGroup.id;
export const securityGroupName = exampleSecurityGroup.name;
// Create a security group with rules managed separately
const controlplaneSecurityGroup = new thalassa.SecurityGroup("controlplaneSecurityGroup", {
    description: "Control plane security group",
    vpcId: exampleVpc.id,
    allowSameGroupTraffic: false,
});
// Create a security group
