thalassa:index/snapshotPolicy:SnapshotPo.description:
Provides a Thalassa Cloud Snapshot Policy resource. This can be used to create, manage, and delete snapshot policies that automatically create snapshots of volumes based on a schedule.

## Example Usage

<!--Start PulumiCodeChooser -->
```typescript
import * as pulumi from "@pulumi/pulumi";
import * as thalassa from "@sandervb2/pulumi-thalassa";

// Create a block volume that will be selected by the snapshot policy
const example = new thalassa.BlockVolume("example", {
    description: "Example block volume for snapshot policy",
    region: "nl-01",
    volumeType: "Block",
    sizeGb: 50,
    labels: {
        backup: "enabled",
        environment: "production",
        service: "database",
    },
});
// Example 1: Snapshot policy using label selector
const selectorExample = new thalassa.SnapshotPolicy("selectorExample", {
    description: "Example snapshot policy using label selector",
    region: "nl-01",
    schedule: "0 2 * * *",
    timezone: "UTC",
    ttl: "30d",
    keepCount: 10,
    enabled: true,
    target: {
        type: "selector",
        selector: {
            backup: "enabled",
            environment: "production",
        },
    },
});
// # Example 2: Snapshot policy targeting specific volumes
const explicitExample = new thalassa.SnapshotPolicy("explicitExample", {
    description: "Example snapshot policy targeting specific volumes",
    region: "nl-01",
    schedule: "0 */6 * * *",
    timezone: "UTC",
    ttl: "7d",
    enabled: true,
    target: {
        type: "explicit",
        volumeIdentities: [example.id],
    },
    labels: {
        "backup-type": "frequent",
    },
});
export const snapshotPolicySelectorId = selectorExample.id;
export const snapshotPolicySelectorName = selectorExample.name;
export const snapshotPolicySelectorNextSnapshotAt = selectorExample.nextSnapshotAt;
export const snapshotPolicyExplicitId = explicitExample.id;
