Create and manage a VPC peering connection

## Example Usage

<!--Start PulumiCodeChooser -->
```typescript
import * as pulumi from "@pulumi/pulumi";
import * as thalassa from "@sandervb2/pulumi-thalassa";

// Create VPCs for peering
const requesterVpcVpc = new thalassa.Vpc("requesterVpcVpc", {
    region: "nl-01",
    cidrs: ["10.0.0.0/16"],
});
const accepterVpcVpc = new thalassa.Vpc("accepterVpcVpc", {
    region: "nl-01",
    cidrs: ["10.1.0.0/16"],
});
// Create VPC peering connection
const example = new thalassa.VpcPeeringConnection("example", {
    description: "Peering connection between two VPCs in the same region",
    requesterVpcId: requesterVpcVpc.id,
    accepterVpcId: accepterVpcVpc.id,
    autoAccept: false,
});
// # Example 1: Accept a peering connection by ID
const acceptById = new thalassa.VpcPeeringConnectionAcceptance("acceptById", {
    peeringConnectionId: example.id,
    waitForActive: true,
    waitForActiveTimeout: 1,
});
const requesterVpcVpcDefaultRouteTable = thalassa.getVpcDefaultRouteTableOutput({
    vpcId: requesterVpcVpc.id,
});
const accepterVpcVpcDefaultRouteTable = thalassa.getVpcDefaultRouteTableOutput({
    vpcId: accepterVpcVpc.id,
});
// Configure route table routes
// Important; routes can only be created after the peering connection has been accepted and has become active
const requesterVpcRouteTableRoute = new thalassa.RouteTableRoute("requesterVpcRouteTableRoute", {
    routeTableId: requesterVpcVpcDefaultRouteTable.apply(requesterVpcVpcDefaultRouteTable => requesterVpcVpcDefaultRouteTable.id),
    destinationCidr: accepterVpcVpc.cidrs[0],
    targetVpcPeeringConnection: acceptById.peeringConnectionId,
});
const accepterVpcRouteTableRoute = new thalassa.RouteTableRoute("accepterVpcRouteTableRoute", {
    routeTableId: accepterVpcVpcDefaultRouteTable.apply(accepterVpcVpcDefaultRouteTable => accepterVpcVpcDefaultRouteTable.id),
    destinationCidr: requesterVpcVpc.cidrs[0],
    targetVpcPeeringConnection: acceptById.peeringConnectionId,
});
